const MAKERS=[{"name": "ダイキン", "icon": "❄️", "summary": "空調専門メーカー。プレミアム冷房、ストリーマ、うるさらシリーズなどが代表的です。", "strengths": ["空調専門メーカー", "プレミアム冷房", "ストリーマ", "スイングコンプレッサー", "室温パトロール"], "recommended": "冷房の快適性や空調メーカーとしての安心感を重視するお客様。", "talk": "冷房の快適さを重視されるなら、空調専門メーカーならではの制御技術が魅力です。"}, {"name": "三菱電機", "icon": "💎", "summary": "霧ヶ峰。ムーブアイなど、センサーを生かした快適制御が代表的です。", "strengths": ["ムーブアイ", "センサー制御", "A.I.自動", "気流制御", "霧ヶ峰"], "recommended": "人のいる場所や体感に合わせた自動運転を重視するお客様。", "talk": "センサーで人やお部屋の状態を見ながら運転するのが特長です。"}, {"name": "パナソニック", "icon": "🌿", "summary": "エオリア。ナノイーXなど、清潔・空気環境に関する機能が代表的です。", "strengths": ["ナノイーX", "エオリアAI", "清潔機能", "エネチャージ搭載機種", "フィルターお掃除"], "recommended": "清潔機能や空気環境を重視するお客様。", "talk": "清潔機能を重視される方には、ナノイーX搭載機種が候補になります。"}, {"name": "日立", "icon": "🐻", "summary": "白くまくん。凍結洗浄など、内部清潔機能が代表的です。", "strengths": ["凍結洗浄", "白くまくん", "熱交換器清潔機能", "ファンお掃除搭載機種"], "recommended": "内部のお手入れを重視するお客様。", "talk": "エアコン内部のお手入れを重視されるなら、凍結洗浄などの清潔機能が魅力です。"}, {"name": "シャープ", "icon": "🌬️", "summary": "プラズマクラスターを搭載し、空気環境や清潔機能を訴求しやすいメーカーです。", "strengths": ["プラズマクラスター", "空気環境", "清潔機能", "気流制御"], "recommended": "空気環境への関心が高いお客様。", "talk": "空気環境を気にされる方には、プラズマクラスター搭載機種が分かりやすい特長です。"}, {"name": "富士通ゼネラル", "icon": "🍃", "summary": "ノクリア。ハイブリッド気流や熱交換器加熱除菌などが代表的です。", "strengths": ["ノクリア", "ハイブリッド気流", "熱交換器加熱除菌", "気流制御"], "recommended": "風の届き方や熱交換器の清潔性を重視するお客様。", "talk": "お部屋全体への風の届き方や清潔性を重視される方に提案しやすいメーカーです。"}, {"name": "東芝", "icon": "⚡", "summary": "プラズマ空清など、空気清浄機能と価格・機能のバランスが特徴です。", "strengths": ["プラズマ空清", "空気清浄", "UV除菌搭載機種", "価格と機能のバランス"], "recommended": "空気清浄機能と価格のバランスを重視するお客様。", "talk": "空気清浄機能も欲しいけれど、価格とのバランスも重視したい方に提案しやすいです。"}];
let quiz=[],index=0,correct=0,locked=false,session=[];
const $=id=>document.getElementById(id);
const screens=["home","levelCategories","quiz","result","makers","makerDetail","scores"];
let selectedLevel="beginner";
function show(id){screens.forEach(x=>$(x).classList.add("hidden"));$(id).classList.remove("hidden");window.scrollTo(0,0);}
function readStats(){return JSON.parse(localStorage.getItem("risaV11Stats")||'{"total":0,"correct":0,"cats":{}}');}
function writeStats(s){localStorage.setItem("risaV11Stats",JSON.stringify(s));}
function refreshHome(){const s=readStats(),rate=s.total?Math.round(s.correct/s.total*100):0;$("total").textContent=s.total;$("rate").textContent=rate+"%";$("rank").textContent=s.total>=500&&rate>=90?"販売マスター":s.total>=250&&rate>=80?"ゴールド":s.total>=100?"ブロンズ":"新人";}
function home(){refreshHome();show("home");}
document.querySelectorAll("[data-home]").forEach(b=>b.onclick=home);
document.querySelectorAll("[data-level]").forEach(b=>b.onclick=()=>openLevel(b.dataset.level));
document.querySelectorAll("[data-level-quiz]").forEach(b=>b.onclick=()=>startQuiz(b.dataset.levelQuiz));
function openLevel(level){
  selectedLevel=level;
  const labels={
    beginner:["🌱 新人","基本をしっかり覚える問題"],
    standard:["🧑‍💼 販売員","実践的な判断問題"],
    master:["👑 エアコンマスター","難しい現場・応用問題"]
  };
  $("levelTitle").textContent=labels[level][0];
  $("levelSub").textContent=labels[level][1];
  show("levelCategories");
}
function startQuiz(cat){
  const levelIndex={beginner:0,standard:1,master:2}[selectedLevel];
  let pool=cat==="today"?[...QUESTIONS]:QUESTIONS.filter(q=>q.cat===cat);
  const leveled=pool.filter((q,i)=>{
    const num=parseInt(q.id.replace("q",""),10);
    return (num-1)%3===levelIndex;
  });
  pool=leveled.length>=5?leveled:pool;
  const count=cat==="today"?5:10;
  quiz=pool.sort(()=>Math.random()-.5).slice(0,Math.min(count,pool.length));
  index=0;correct=0;session=[];
  const levelName={beginner:"新人",standard:"販売員",master:"エアコンマスター"}[selectedLevel];
  $("quizTitle").textContent=(cat==="today"?"今日の5問":cat)+"｜"+levelName;
  show("quiz");
  renderQuestion();
}
function renderQuestion(){
  locked=false;
  const q=quiz[index];
  $("progressText").textContent=`問題 ${index+1} / ${quiz.length}`;
  $("barFill").style.width=(index/quiz.length*100)+"%";
  $("category").textContent=q.cat;
  $("question").textContent=q.q;
  $("choices").innerHTML="";
  $("explain").classList.add("hidden");
  $("next").classList.add("hidden");

  const shuffled=q.choices.map((text,originalIndex)=>({
    text,
    isCorrect:originalIndex===q.answer
  })).sort(()=>Math.random()-.5);

  shuffled.forEach(item=>{
    const b=document.createElement("button");
    b.textContent=item.text;
    b.dataset.correct=item.isCorrect?"1":"0";
    b.onclick=()=>answer(b);
    $("choices").appendChild(b);
  });
}
function answer(button){
  if(locked)return;
  locked=true;
  const q=quiz[index];
  const ok=button.dataset.correct==="1";
  if(ok)correct++;
  session.push({cat:q.cat,ok});

  [...$("choices").children].forEach(b=>{
    if(b.dataset.correct==="1")b.classList.add("correct");
    if(b===button&&!ok)b.classList.add("wrong");
  });

  $("explain").innerHTML=`<strong>${ok?"⭕ 正解！":"❌ 不正解"}</strong><br>${q.exp}<hr><strong>販売ポイント</strong><br>${q.tip}`;
  $("explain").classList.remove("hidden");
  $("next").classList.remove("hidden");
}
$("next").onclick=()=>{index++;index<quiz.length?renderQuestion():finish();};
function finish(){const s=readStats();s.total+=session.length;s.correct+=session.filter(x=>x.ok).length;session.forEach(x=>{if(!s.cats[x.cat])s.cats[x.cat]={total:0,correct:0};s.cats[x.cat].total++;if(x.ok)s.cats[x.cat].correct++;});writeStats(s);$("scoreValue").textContent=Math.round(correct/quiz.length*100);$("scoreText").textContent=`${correct} / ${quiz.length}問正解`;show("result");}
$("makerBtn").onclick=showMakers;$("makerQuiz").onclick=()=>startQuiz("メーカー別特徴");
function showMakers(){$("makerList").innerHTML=MAKERS.map((m,i)=>`<div class="makerCard" data-i="${i}"><h3>${m.icon} ${m.name}</h3><p>${m.summary}</p></div>`).join("");[...$("makerList").children].forEach(c=>c.onclick=()=>showMaker(Number(c.dataset.i)));show("makers");}
function showMaker(i){const m=MAKERS[i];$("makerName").textContent=`${m.icon} ${m.name}`;$("makerContent").innerHTML=`<div class="infoCard"><h3>特徴</h3><p>${m.summary}</p><div class="chips">${m.strengths.map(x=>`<span class="chip">${x}</span>`).join("")}</div></div><div class="infoCard"><h3>おすすめのお客様</h3><p>${m.recommended}</p></div><div class="infoCard"><h3>30秒トーク</h3><p>${m.talk}</p></div>`;show("makerDetail");}
$("backMakers").onclick=showMakers;$("backLevel").onclick=()=>show("levelCategories");
$("scoreBtn").onclick=()=>{const s=readStats(),r=s.total?Math.round(s.correct/s.total*100):0;$("sTotal").textContent=s.total;$("sCorrect").textContent=s.correct;$("sRate").textContent=r+"%";$("categoryScores").innerHTML=Object.entries(s.cats).map(([k,v])=>`<div class="catCard"><h3>${k}</h3><p>${v.total}問中 ${v.correct}問正解（${Math.round(v.correct/v.total*100)}%）</p></div>`).join("")||"<p>まだ成績がありません。</p>";show("scores");};
home();